PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE orders (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      product_title TEXT NOT NULL,
      image_url TEXT,
      image_path TEXT,
      category TEXT,
      price REAL,
      seller_id TEXT,
      order_date TEXT,
      created_at TEXT DEFAULT (datetime('now'))
    );
CREATE TABLE candidates (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      image_url TEXT,
      image_path TEXT,
      source TEXT,
      ali_product_id TEXT,
      price REAL,
      shipping_cost REAL,
      score REAL,
      status TEXT DEFAULT 'new',
      created_at TEXT DEFAULT (datetime('now'))
    , immigrant_name TEXT, immigrant_description TEXT, retail_price REAL, price_reasoning TEXT, image_flags TEXT, processed_images TEXT, shopify_product_id TEXT, score_breakdown TEXT, namer_data TEXT, cj_product_id TEXT, product_url TEXT, gender TEXT DEFAULT 'unisex', detected_category TEXT);
CREATE TABLE taste_profile (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      key TEXT NOT NULL,
      value TEXT NOT NULL,
      created_at TEXT DEFAULT (datetime('now'))
    );
CREATE TABLE swipe_decisions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      candidate_id INTEGER NOT NULL,
      decision TEXT NOT NULL CHECK(decision IN ('approve', 'reject')),
      batch_number INTEGER,
      created_at TEXT DEFAULT (datetime('now')),
      FOREIGN KEY (candidate_id) REFERENCES candidates(id)
    );
CREATE TABLE image_processing (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      candidate_id INTEGER NOT NULL,
      original_url TEXT,
      processed_path TEXT,
      flags TEXT,
      hidden INTEGER DEFAULT 0,
      sort_order INTEGER DEFAULT 0,
      created_at TEXT DEFAULT (datetime('now')),
      FOREIGN KEY (candidate_id) REFERENCES candidates(id)
    );
DELETE FROM sqlite_sequence;
COMMIT;
